        const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<title>${escHtml(shareMeta.title)} | Iskryb</title>
<meta name="description" content="${escHtml(shareMeta.description)}">
${fbAppIdTag}
