// ── Profile share route: composite OG image for social media ──
app.get('/share/u/:username/image', async (req, res) => {
    const { username } = req.params;
    await ensureShareFonts();

    try {
        const result = await getUserByUsernameService(username);
        const user = result?.userData?.[0];
        if (!user) {
            return res.redirect(302, DEFAULT_OG_IMAGE_URL);
        }

        const displayName = normalizeWhitespace(user.name) || username;
        const handle = `@${normalizeWhitespace(user.username || username)}`;
        const bio = toPreviewText(user.bio || '', 120);

        // ── Fetch background image ──
        let bgBuffer = null;
        const bgStyle = user.background || {};
        const bgImageMatch = typeof bgStyle.backgroundImage === 'string'
            ? bgStyle.backgroundImage.match(/url\(["']?([^"')]+)["']?\)/)
            : null;
        const bgImageUrl = bgImageMatch?.[1];

        if (bgImageUrl) {
            const bgEval = evaluateShareImageCandidate(bgImageUrl);
            if (bgEval.ok && bgEval.resolvedUrl) {
                try {
                    const remote = await fetchRemoteImageBuffer(bgEval.resolvedUrl);
                    bgBuffer = remote.buffer;
                } catch { /* use fallback gradient */ }
            }
        }

        // ── Base layer: background or dark gradient ──
        let baseLayer;
        if (bgBuffer) {
            baseLayer = await sharp(bgBuffer, { limitInputPixels: 60_000_000 })
                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, { fit: 'cover' })
                .toBuffer();
        } else {
            // Use profile's solid background color if available, otherwise dark fallback
            const solidColor = (typeof bgStyle.background === 'string' && /^#[0-9a-fA-F]{3,8}$/.test(bgStyle.background.trim()))
                ? bgStyle.background.trim()
                : null;
            const gradientSvg = solidColor
                ? `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
                    <rect width="100%" height="100%" fill="${solidColor}"/>
                </svg>`
                : `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
                    <defs><linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="100%">
                        <stop offset="0%" stop-color="#1a1a2e"/>
                        <stop offset="100%" stop-color="#16213e"/>
                    </linearGradient></defs>
                    <rect width="100%" height="100%" fill="url(#g)"/>
                </svg>`;
            baseLayer = await sharp(Buffer.from(gradientSvg))
                .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT)
                .png()
                .toBuffer();
        }

        // ── Dark overlay for text readability ──
        const overlaySvg = `<svg width="${DEFAULT_OG_IMAGE_WIDTH}" height="${DEFAULT_OG_IMAGE_HEIGHT}">
            <rect width="100%" height="100%" fill="black" fill-opacity="0.55"/>
        </svg>`;
        const overlayBuffer = await sharp(Buffer.from(overlaySvg)).png().toBuffer();

        // ── Circular avatar ──
        let avatarComposite = null;
        const avatarSize = 180;
        const avatarUrl = user.image_url;
        if (avatarUrl) {
            const avatarEval = evaluateShareImageCandidate(avatarUrl);
            if (avatarEval.ok && avatarEval.resolvedUrl) {
                try {
                    const remote = await fetchRemoteImageBuffer(avatarEval.resolvedUrl);
                    const circleMask = Buffer.from(
                        `<svg width="${avatarSize}" height="${avatarSize}">
                            <circle cx="${avatarSize / 2}" cy="${avatarSize / 2}" r="${avatarSize / 2}" fill="white"/>
                        </svg>`
                    );
                    const resizedAvatar = await sharp(remote.buffer, { limitInputPixels: 60_000_000 })
                        .resize(avatarSize, avatarSize, { fit: 'cover' })
                        .png()
                        .toBuffer();
                    const circularAvatar = await sharp(resizedAvatar)
                        .composite([{ input: circleMask, blend: 'dest-in' }])
                        .png()
                        .toBuffer();
                    avatarComposite = circularAvatar;
                } catch { /* skip avatar */ }
            }
        }

        // ── Text overlays using Sharp text API (bypasses fontconfig) ──
        const nameY = avatarComposite ? 340 : 240;
        const handleY = nameY + 50;
        const bioY = handleY + 50;
        const brandY = DEFAULT_OG_IMAGE_HEIGHT - 50;

        const escapeMarkup = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

        async function makeTextImage(text, { fontfile, fontSize, opacity = 1, maxWidth = DEFAULT_OG_IMAGE_WIDTH }) {
            let buf = await sharp({
                text: {
                    text: `<span foreground="white" size="${Math.round(fontSize * 1024)}">${escapeMarkup(text)}</span>`,
                    fontfile,
                    rgba: true,
                    width: maxWidth,
                    align: 'centre',
                    dpi: 72,
                },
            }).png().toBuffer();
            if (opacity < 1) {
                buf = await sharp(buf)
                    .linear([1, 1, 1, opacity], [0, 0, 0, 0])
                    .png()
                    .toBuffer();
            }
            return buf;
        }

        // ── Compose all layers ──
        const composites = [
            { input: overlayBuffer, top: 0, left: 0 },
        ];

        if (avatarComposite) {
            const avatarLeft = Math.round((DEFAULT_OG_IMAGE_WIDTH - avatarSize) / 2);
            composites.push({ input: avatarComposite, top: 100, left: avatarLeft });
        }

        // Name (bold)
        const nameBuf = await makeTextImage(displayName, { fontfile: FONT_BOLD_PATH, fontSize: 48 });
        const nameMeta = await sharp(nameBuf).metadata();
        composites.push({ input: nameBuf, top: Math.max(0, nameY - nameMeta.height), left: Math.round((DEFAULT_OG_IMAGE_WIDTH - nameMeta.width) / 2) });

        // Handle
        const handleBuf = await makeTextImage(handle, { fontfile: FONT_PATH, fontSize: 28, opacity: 0.7 });
        const handleMeta = await sharp(handleBuf).metadata();
        composites.push({ input: handleBuf, top: Math.max(0, handleY - handleMeta.height), left: Math.round((DEFAULT_OG_IMAGE_WIDTH - handleMeta.width) / 2) });

        // Bio
        if (bio) {
            const bioBuf = await makeTextImage(bio, { fontfile: FONT_PATH, fontSize: 24, opacity: 0.85, maxWidth: DEFAULT_OG_IMAGE_WIDTH - 100 });
            const bioMeta = await sharp(bioBuf).metadata();
            composites.push({ input: bioBuf, top: Math.max(0, bioY - bioMeta.height), left: Math.round((DEFAULT_OG_IMAGE_WIDTH - bioMeta.width) / 2) });
        }

        // Brand
        const brandBuf = await makeTextImage('iskrib.com', { fontfile: FONT_BOLD_PATH, fontSize: 22, opacity: 0.5 });
        const brandMeta = await sharp(brandBuf).metadata();
        composites.push({ input: brandBuf, top: Math.max(0, brandY - brandMeta.height), left: Math.round((DEFAULT_OG_IMAGE_WIDTH - brandMeta.width) / 2) });

        const finalImage = await sharp(baseLayer)
            .composite(composites)
            .jpeg({ quality: 82, mozjpeg: true })
            .toBuffer();

        res.set('Content-Type', 'image/jpeg');
        res.set('Cache-Control', 'public, max-age=3600');
        return res.send(finalImage);
    } catch (err) {
        console.error('profile share image route error:', err?.message || err);
        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
    }
});

